fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> i64 {
    const MOD: i64 = 10_0000_0007;
    let n = nums.len();
    let mut multipliers = vec![0; n];

    for query in queries {
        let li = query[0];
        let ri = query[1];
        let ki = query[2];
        let vi = query[3];

        let mut idx = li;
        while idx <= ri {
            multipliers[idx] += vi;
            idx += ki;
        }
    }

    let mut result = 0;
    for i in 0..n {
        let mut val = nums[i];
        for _ in 0..multipliers[i] {
            val = (val * vi) % MOD;
        }
        result ^= val;
    }

    result
}
